import SwiftUI

@main
struct MyAppApp: App {
    @StateObject var promoHandler = PromoHandler()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoHandler)
                .onContinueUserActivity(NSUserActivityTypeBrowsingWeb) { userActivity in
                    if let url = userActivity.webpageURL {
                        promoHandler.handlePromoURL(url)
                    }
                }
        }
    }
}

