PromoHandler.swift
import Foundation
import Combine

class PromoHandler: ObservableObject {
    @Published var promoCode: String?
    @Published var varDiscount: String?

    func handlePromoURL(_ url: URL) {
        // Ensure the URL matches the expected domain and path for your universal link
        // For this example, we expect https://myapp.com/promo
        guard url.host == "myapp.com", url.path == "/promo" else {
            // Reset promo data if the URL is not a recognized promo link
            promoCode = nil
            varDiscount = nil
            return
        }

        if let components = URLComponents(url: url, resolvingAgainstBaseURL: false) {
            promoCode = components.queryItems?.first(where: { $0.name == "code" })?.value
            varDiscount = components.queryItems?.first(where: { $0.name == "discount" })?.value
        }
    }
}

